using UnityEngine;

public class InputExample : MonoBehaviour
{
    void Update()
    {
        // --- Keyboard Input ---

        // GetAxis — smooth, analog input (-1 to 1)
        float horizontal = Input.GetAxis("Horizontal");
        float vertical = Input.GetAxis("Vertical");

        if (horizontal != 0 || vertical != 0)
        {
            Debug.Log("Movement: (" + horizontal + ", " + vertical + ")");
        }

        // GetAxisRaw — immediate, digital input (-1, 0, 1)
        float rawHorizontal = Input.GetAxisRaw("Horizontal");

        // GetKey — key down events
        if (Input.GetKeyDown(KeyCode.Space))
        {
            Debug.Log("Space pressed!");
        }

        if (Input.GetKey(KeyCode.W))
        {
            Debug.Log("W held down!");
        }

        if (Input.GetKeyUp(KeyCode.LeftShift))
        {
            Debug.Log("Shift released!");
        }

        // --- Mouse Input ---

        // Mouse position
        Vector3 mousePosition = Input.mousePosition;
        // Debug.Log("Mouse position: " + mousePosition);

        // Mouse buttons
        if (Input.GetMouseButtonDown(0))  // Left click
        {
            Debug.Log("Left mouse clicked!");
            Debug.Log("Position: " + Input.mousePosition);
        }

        if (Input.GetMouseButton(1))  // Right click held
        {
            Debug.Log("Right mouse held!");
        }

        // --- Other Input ---

        // Any key
        if (Input.anyKeyDown)
        {
            Debug.Log("A key was pressed!");
        }

        // Touch input (for mobile)
        if (Input.touchCount > 0)
        {
            Touch touch = Input.GetTouch(0);
            Debug.Log("Touch position: " + touch.position);
        }

        // --- Input Actions (New Input System) ---
        // Note: This requires the Input System package
        // public PlayerControls controls;
        // controls = new PlayerControls();
        // controls.Enable();
        // controls.Player.Move.performed += ctx => { /* ... */ };
    }

    // Example: Simple movement with GetAxis
    void MovePlayer()
    {
        float moveX = Input.GetAxis("Horizontal");
        float moveY = Input.GetAxis("Vertical");

        Vector3 direction = new Vector3(moveX, moveY, 0);
        transform.Translate(direction * 5f * Time.deltaTime);
    }

    // Example: Jump with GetButtonDown
    void Jump()
    {
        if (Input.GetButtonDown("Jump"))
        {
            Debug.Log("Jump!");
        }
    }
}

